import { useState, useEffect, useRef, useCallback } from 'react';
import { updateLocation, updateDestinationLocation } from '../lib/firebase';
import { bufferLocation, flushBuffer, isOnline } from '../lib/offline';
import { getUpdateInterval } from '../lib/adaptive';

/**
 * Custom hook for tracking the user's geolocation.
 * Adapts update frequency based on current status.
 * Buffers locations offline and syncs when back online.
 *
 * @param {string|null} sessionId - Active Firebase session ID
 * @param {'sender'|'receiver'} role - Role of the current user
 * @param {string} status - Current tracking status
 * @param {boolean} active - Whether tracking is active
 * @returns {{ position: { lat, lng } | null, error: string | null, isTracking: boolean }}
 */
export function useGeolocation(sessionId, role = 'sender', status = 'far', active = true) {
  const [position, setPosition] = useState(null);
  const [error, setError] = useState(null);
  const [isTracking, setIsTracking] = useState(false);
  const watchIdRef = useRef(null);
  const intervalRef = useRef(null);
  const lastSendRef = useRef(0);

  const sendLocation = useCallback(
    async (lat, lng, speed) => {
      if (!sessionId) return;

      const point = { lat, lng, timestamp: Date.now(), speed };
      bufferLocation(point);

      if (isOnline()) {
        try {
          const updateFn = role === 'sender' ? updateLocation : updateDestinationLocation;
          await updateFn(sessionId, lat, lng, speed);
          // Also flush any buffered points
          await flushBuffer(sessionId, updateFn);
        } catch (e) {
          console.warn('Failed to send location:', e);
        }
      }
    },
    [sessionId, role]
  );

  useEffect(() => {
    if (!active || !sessionId || status === 'reached') {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
        watchIdRef.current = null;
      }
      setIsTracking(false);
      return;
    }

    if (!navigator.geolocation) {
      setError('Geolocation is not supported by this browser');
      return;
    }

    setIsTracking(true);

    // Watch position continuously
    watchIdRef.current = navigator.geolocation.watchPosition(
      (pos) => {
        const { latitude, longitude, speed } = pos.coords;
        setPosition({ lat: latitude, lng: longitude });
        setError(null);

        const interval = getUpdateInterval(status);
        const now = Date.now();

        // Respect adaptive interval
        if (now - lastSendRef.current >= interval) {
          lastSendRef.current = now;
          sendLocation(latitude, longitude, speed || 0);
        }
      },
      (err) => {
        setError(err.message);
        console.warn('Geolocation error:', err);
      },
      {
        enableHighAccuracy: true,
        maximumAge: 5000,
        timeout: 10000,
      }
    );

    // Set up periodic flush for offline buffered data
    const flushInterval = setInterval(() => {
      if (isOnline() && sessionId) {
        const updateFn = role === 'sender' ? updateLocation : updateDestinationLocation;
        flushBuffer(sessionId, updateFn);
      }
    }, 15000);

    return () => {
      if (watchIdRef.current !== null) {
        navigator.geolocation.clearWatch(watchIdRef.current);
        watchIdRef.current = null;
      }
      clearInterval(flushInterval);
      setIsTracking(false);
    };
  }, [sessionId, status, active, sendLocation]);

  // Listen for online/offline events to flush buffer
  useEffect(() => {
    const handleOnline = () => {
      if (sessionId) {
        const updateFn = role === 'sender' ? updateLocation : updateDestinationLocation;
        flushBuffer(sessionId, updateFn);
      }
    };

    window.addEventListener('online', handleOnline);
    return () => window.removeEventListener('online', handleOnline);
  }, [sessionId, role]);

  return { position, error, isTracking };
}

import { useState, useCallback } from 'react';
import { createSession } from '../lib/firebase';
import './Home.css';

/**
 * Home / Share screen.
 * Simplified P2P Flow:
 * 1. User clicks "Share Live Location"
 * 2. Gets GPS, creates session (destination is null)
 * 3. Shows sharing link.
 */
export default function Home() {
  const [step, setStep] = useState('ready'); // ready | detecting | sharing
  const [sessionId, setSessionId] = useState(null);
  const [shareLink, setShareLink] = useState('');
  const [error, setError] = useState(null);
  const [copied, setCopied] = useState(false);

  const handleStartSharing = useCallback(async () => {
    setError(null);
    setStep('detecting');

    if (!navigator.geolocation) {
      setError('Geolocation is not supported by your browser');
      setStep('ready');
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const lat = pos.coords.latitude;
          const lng = pos.coords.longitude;

          const id = await createSession(lat, lng);

          // Identify this device as the sender for this session
          localStorage.setItem(`reachio_role_${id}`, 'sender');

          setSessionId(id);
          const link = `${window.location.origin}/track/${id}`;
          setShareLink(link);
          setStep('sharing');
        } catch (e) {
          console.error('Failed to start sharing:', e);
          setError(e.message || 'Failed to start sharing. Check your connection.');
          setStep('ready');
        }
      },
      (err) => {
        setError('Unable to get your location. Please enable location services and try again.');
        setStep('ready');
      },
      { enableHighAccuracy: true, timeout: 15000 }
    );
  }, []);

  const handleCopy = useCallback(() => {
    navigator.clipboard.writeText(shareLink).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  }, [shareLink]);

  const handleShareWhatsApp = useCallback(() => {
    const text = encodeURIComponent(`Track my live location on Reachio ≡ƒôì: ${shareLink}`);
    window.open(`https://wa.me/?text=${text}`, '_blank');
  }, [shareLink]);

  return (
    <div className="home">
      <div className="home-bg" />

      <header className="home-header">
        <div className="logo">
          <span className="logo-icon">≡ƒôì</span>
          <h1>Reachio</h1>
        </div>
        <p className="tagline">Real-time peer-to-peer location sharing.</p>
      </header>

      <div className="home-card">
        {step === 'sharing' ? (
          <div className="share-active">
            <div className="share-active-icon">≡ƒƒó</div>
            <h2>You're Live!</h2>
            <p className="share-active-desc">Send this link to the person you are meeting.</p>

            <div className="share-link-box">
              <input type="text" value={shareLink} readOnly className="share-link-input" />
              <button className="btn btn-copy" onClick={handleCopy}>
                {copied ? 'Γ£ô Copied!' : 'Copy'}
              </button>
            </div>

            <div className="share-actions">
              <button className="btn btn-whatsapp" onClick={handleShareWhatsApp}>
                <span>≡ƒô▒</span> Share via WhatsApp
              </button>
              <a href={shareLink} className="btn btn-outline" target="_blank" rel="noopener">
                View My Tracker ΓåÆ
              </a>
            </div>
          </div>
        ) : step === 'detecting' ? (
          <div className="detecting">
            <div className="detecting-spinner" />
            <p>Accessing GPS & Creating Session...</p>
          </div>
        ) : (
          <div className="share-setup">
            <h2>Track & Meet Instantly</h2>
            <p style={{ color: 'rgba(255,255,255,0.6)', margin: '0 0 24px 0', lineHeight: 1.5 }}>
              Share your live location. When your friend opens the link, the app automatically finds them and shows exactly how far apart you are!
            </p>

            {error && <div className="error-msg">{error}</div>}

            <button
              className="btn btn-primary btn-large"
              onClick={handleStartSharing}
            >
              ≡ƒôí Share My Live Location
            </button>
          </div>
        )}
      </div>

      <div className="features">
        <div className="feature">
          <span className="feature-icon">≡ƒôÅ</span>
          <span>Live Distance</span>
        </div>
        <div className="feature">
          <span className="feature-icon">ΓÅ▒∩╕Å</span>
          <span>Adaptive ETA</span>
        </div>
        <div className="feature">
          <span className="feature-icon">≡ƒöù</span>
          <span>P2P Tracking</span>
        </div>
        <div className="feature">
          <span className="feature-icon">≡ƒÜ½</span>
          <span>No Login Required</span>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useParams } from 'react-router-dom';
import { useFirebaseSession } from '../hooks/useFirebaseSession';
import { useGeolocation } from '../hooks/useGeolocation';
import { useETA } from '../hooks/useETA';
import { haversineDistance, smoothValue, formatDistance } from '../lib/distance';
import { getStatus } from '../lib/status';
import { isOnline } from '../lib/offline';
import MapView from '../components/Map';
import BottomPanel from '../components/BottomPanel';
import './Track.css';

/**
 * Tracking page (P2P).
 * Handles both Sender (broadcasting origin) and Receiver (broadcasting destination).
 */
export default function Track() {
  const { sessionId } = useParams();
  const { session, loading, error } = useFirebaseSession(sessionId);
  const [smoothedDistance, setSmoothedDistance] = useState(null);
  const [online, setOnline] = useState(navigator.onLine);
  const prevDistRef = useRef(null);

  // Determine role based on who created the session
  const role = localStorage.getItem(`reachio_role_${sessionId}`) === 'sender' ? 'sender' : 'receiver';

  // Start broadcasting our own location (if sender, updates sender; if receiver, updates destination)
  const { position: myLivePos, error: geoError, isTracking } = useGeolocation(sessionId, role, 'far', true);

  // Track online/offline status
  useEffect(() => {
    const handleOnline = () => setOnline(true);
    const handleOffline = () => setOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const senderPos = session?.sender
    ? { lat: session.sender.lat, lng: session.sender.lng }
    : (role === 'sender' && myLivePos ? myLivePos : null);

  const destPos = session?.destination
    ? { lat: session.destination.lat, lng: session.destination.lng }
    : (role === 'receiver' && myLivePos ? myLivePos : null);

  const rawDistance = senderPos && destPos
    ? haversineDistance(senderPos.lat, senderPos.lng, destPos.lat, destPos.lng)
    : null;

  useEffect(() => {
    if (rawDistance !== null) {
      const smoothed = smoothValue(rawDistance, prevDistRef.current, 0.3);
      prevDistRef.current = smoothed;
      setSmoothedDistance(smoothed);
    }
  }, [rawDistance]);

  const status = smoothedDistance !== null ? getStatus(smoothedDistance) : 'far';
  const distanceText = smoothedDistance !== null ? formatDistance(smoothedDistance) : '--';

  const { etaText } = useETA(
    senderPos,
    destPos,
    smoothedDistance || 0,
    session?.sender?.speed || 0
  );

  if (loading) {
    return (
      <div className="track-loading">
        <div className="track-loading-spinner" />
        <span>Connecting to session...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="track-error">
        <span className="track-error-icon">Γ¥î</span>
        <h2>Session Not Found</h2>
        <p>This tracking link may have expired or is invalid.</p>
        <a href="/" className="btn btn-primary">Create a New Session</a>
      </div>
    );
  }

  const isWaitingForReceiver = role === 'sender' && !session?.destination;

  return (
    <div className="track">
      {/* Map layer */}
      <MapView senderPos={senderPos} destinationPos={destPos} status={status} />

      {/* Top bar */}
      <div className="track-topbar">
        <div className="topbar-logo">
          <span>≡ƒôì</span> Reachio
        </div>
        {!online && (
          <div className="offline-banner">
            <span>≡ƒôí</span> Offline ΓÇö Showing last known position
          </div>
        )}
      </div>

      {/* Waiting Overlay for Sender */}
      {isWaitingForReceiver && (
        <div className="waiting-overlay">
          <div className="waiting-card">
            <div className="detecting-spinner" style={{ marginBottom: 16 }} />
            <h3>Waiting for receiver...</h3>
            <p>Your location is live. When your friend opens the link, you will see their position here.</p>
          </div>
        </div>
      )}

      {geoError && (
        <div className="geo-error-banner">
          ΓÜá∩╕Å Location Error: {geoError}
        </div>
      )}

      {/* Bottom panel */}
      {senderPos && destPos && !isWaitingForReceiver && (
        <BottomPanel
          distance={distanceText}
          etaText={etaText}
          status={status}
          isOnline={online}
        />
      )}
    </div>
  );
}
